mapper.sql:
/* wms-outbound-obOrdSep-sql-oracle.xml - selectObBaseRefSql - WMS > 출고 관리 > 출고편집 조회 SQL */ SELECT ROW_NUMBER() OVER (ORDER BY CTKEY, OBORDKEY) AS RNO , OB.* FROM ( SELECT OH.CTKEY /*센터코드*/ , OH.OWKEY /*화주코드*/ , OH.OBHDDAY /*주문지시일시*/ , OH.OBREQDATE /*출고희망일자*/ , OH.OBORDKEY /*오더코드*/ , OH.OBHDKEY /*릴리즈코드*/ , OH.EXTERNORDERKEY /*고객주문번호*/ , OH.OBHDTYPECD /*출고유형*/ , OH.OBSTATUSCD /*출고상태*/ , OH.ORDSEPTYPECD /*주문유형*/ , OH.WKTYPECD /*작업유형*/ , OH.WBLNO /*송장번호*/ , OH.RECOMBOXBARCODE /*추천박스*/ , BOX.BOXNM /*추천박스명*/ , OH.CMT /*비고*/ , OH.ORDSEPURKEY /*주문분리자*/ , OH.ORDSEPDATE /*주문분리일시*/ , OH.INSERTURKEY /*등록자*/ , OH.INSERTDATE /*등록일시*/ , OH.UPDATEURKEY /*수정자*/ , OH.UPDATEDATE /*수정일시*/ , OH.WAHDKEY , OH.CLASSIFSPECCD , OH.OBWKISTURKEY , MAX(GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0))) AS MAXLEN /*상품길이*/ , (CASE WHEN SUM(CASE WHEN OD.EXPCTQTY > COALESCE(ICUTXCTN.ICUNITQTY, 0) THEN 1 ELSE 0 END) > 0 THEN 'O' WHEN SUM(CASE WHEN OD.EXPCTQTY = COALESCE(ICUTXCTN.ICUNITQTY, 0) THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS CTN_YN /*카톤입수여부*/ , (CASE WHEN SUM(CASE WHEN OD.EXPCTQTY > COALESCE(ICUTXINN.ICUNITQTY, 0) THEN 1 ELSE 0 END) > 0 THEN 'O' WHEN SUM(CASE WHEN OD.EXPCTQTY = COALESCE(ICUTXINN.ICUNITQTY, 0) THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS INN_YN /*중포입수여부*/ , (CASE WHEN SUM(CASE IC.PKOTICYN WHEN 'Y' THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS PKOTICYN /*덕용여부*/ , (CASE WHEN SUM(CASE IC.ROBSORTERICYN WHEN 'Y' THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE 'N' END) AS ROBSORTERICYN /*로봇여부*/ , COUNT(OD.ICKEY) AS SKU , SUM(OD.EXPCTQTY) AS PCS , TRUNC( SUM( CASE WHEN IC.PCKGOVLPYN = 'Y' THEN ((COALESCE(ICUTX.WIDTH, 0) + (COALESCE(IC.OVLPPCKGWIDTHVAL, 0) * (OD.INITQTY- 1::INTEGER))) * (COALESCE(ICUTX.DEPTH, 0) + (COALESCE(IC.OVLPPCKGDEPTHVAL, 0) * (OD.INITQTY- 1::INTEGER))) * (COALESCE(ICUTX.HEIGHT, 0) + (COALESCE(IC.OVLPPCKGHEIGHTVAL, 0) * (OD.INITQTY- 1::INTEGER)))) * 0.000000001 ELSE COALESCE(ICUTX.VOL, 0) * OD.INITQTY END ), 7) AS CBM /*총CBM*/ , (OH.WEIGHT / 1000) AS WEIGHT /*총중량*/ , SUM(CASE WHEN IC.ROBSORTERICYN = 'N' THEN OD.EXPCTQTY ELSE 0 END) AS FBQTY /*이형물QTY*/ , SUM(IC.SLPRC * OD.EXPCTQTY) AS TOT_SLPRC /*총단가*/ , MAX(CASE WHEN OH.ORDSEPTYPECD = '10' AND OD.EXPCTQTY >= ICUTXCTN.ICUNITQTY THEN (CASE WHEN GREATEST(COALESCE(ICUTXCTN.WIDTH, 0), COALESCE(ICUTXCTN.DEPTH, 0), COALESCE(ICUTXCTN.HEIGHT, 0)) <= 500 AND (ICUTXCTN.WIDTH + ICUTXCTN.DEPTH + ICUTXCTN.HEIGHT - GREATEST(COALESCE(ICUTXCTN.WIDTH, 0), COALESCE(ICUTXCTN.DEPTH, 0), COALESCE(ICUTXCTN.HEIGHT, 0)) - LEAST(COALESCE(ICUTXCTN.WIDTH, 0), COALESCE(ICUTXCTN.DEPTH, 0), COALESCE(ICUTXCTN.HEIGHT, 0))) <= 500 AND LEAST(COALESCE(ICUTXCTN.WIDTH, 0), COALESCE(ICUTXCTN.DEPTH, 0), COALESCE(ICUTXCTN.HEIGHT, 0)) <= 350 THEN 'Y' ELSE 'N' END) ELSE NULL END) AS AUTOLBYN_CTN /*카톤오토라벨러가능여부*/ , MAX(CASE WHEN OH.ORDSEPTYPECD = '10' AND OD.EXPCTQTY >= ICUTXINN.ICUNITQTY THEN (CASE WHEN GREATEST(COALESCE(ICUTXINN.WIDTH, 0), COALESCE(ICUTXINN.DEPTH, 0), COALESCE(ICUTXINN.HEIGHT, 0)) <= 500 AND (ICUTXINN.WIDTH + ICUTXINN.DEPTH + ICUTXINN.HEIGHT - GREATEST(COALESCE(ICUTXINN.WIDTH, 0), COALESCE(ICUTXINN.DEPTH, 0), COALESCE(ICUTXINN.HEIGHT, 0)) - LEAST(COALESCE(ICUTXINN.WIDTH, 0), COALESCE(ICUTXINN.DEPTH, 0), COALESCE(ICUTXINN.HEIGHT, 0))) <= 500 AND LEAST(COALESCE(ICUTXINN.WIDTH, 0), COALESCE(ICUTXINN.DEPTH, 0), COALESCE(ICUTXINN.HEIGHT, 0)) <= 350 THEN 'Y' ELSE 'N' END) ELSE NULL END) AS AUTOLBYN_INN /*중포오토라벨러가능여부*/ FROM TWORK_INFO_OB_HD OH
INNER JOIN ( SELECT OH.CTKEY , OH.OWKEY , OH.OBHDKEY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD WHERE OH.CTKEY = #{CTKEY}
AND OH.OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND OH.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO}
AND OD.ICKEY IN
#{ickey}
AND IC.HIGHFRQNCYDMGYN = #{HIGHFRQNCYDMGYN}
AND (ICUTX.VOL * OD.EXPCTQTY) > #{OVERSCHEDIT}
AND (ICUTX.WEIGHT * OD.EXPCTQTY) / 1000 > #{OVERSCHEDIT}
AND OD.EXPCTQTY > #{OVERSCHEDIT}
AND IC.SLPRC * OD.EXPCTQTY > #{OVERSCHEDIT}
AND GREATEST(COALESCE(ICUTX.WIDTH, 0), COALESCE(ICUTX.DEPTH, 0), COALESCE(ICUTX.HEIGHT, 0)) BETWEEN #{MAXLENFR} AND #{MAXLENTO}
GROUP BY OH.CTKEY , OH.OWKEY , OH.OBHDKEY ) FIL ON OH.CTKEY = FIL.CTKEY AND OH.OWKEY = FIL.OWKEY AND OH.OBHDKEY = FIL.OBHDKEY
INNER JOIN ( SELECT CTKEY , OWKEY , OBHDKEY FROM ( SELECT OH.CTKEY , OH.OWKEY , OH.OBHDKEY , SUM(CASE WHEN OD.ICKEY IN
#{ickey}
THEN 1 ELSE 0 END) IN_CNT , SUM(CASE WHEN OD.ICKEY NOT IN
#{ickey}
THEN 1 ELSE 0 END) OUT_CNT , COUNT(*) CNT FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY WHERE OH.CTKEY = #{CTKEY} AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.WAHDKEY IS NULL
AND OH.OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND OH.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO} GROUP BY OH.CTKEY , OH.OWKEY , OH.OBHDKEY ) WHERE IN_CNT > 0 AND OUT_CNT = 0 ) INCICKEY ON OH.CTKEY = INCICKEY.CTKEY AND OH.OWKEY = INCICKEY.OWKEY AND OH.OBHDKEY = INCICKEY.OBHDKEY
INNER JOIN TWORK_INFO_OB_DT OD ON OH.CTKEY = OD.CTKEY AND OH.OWKEY = OD.OWKEY AND OH.OBHDKEY = OD.OBHDKEY INNER JOIN TWORK_MST_IC IC ON OD.CTKEY = IC.CTKEY AND OD.OWKEY = IC.OWKEY AND OD.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_ICUTXTYPE ICUTX ON OD.CTKEY = ICUTX.CTKEY AND OD.OWKEY = ICUTX.OWKEY AND OD.ICKEY = ICUTX.ICKEY AND OD.ICUNITKEY = ICUTX.ICUNITKEY AND OD.UOM = ICUTX.ICUNITTYPECD LEFT OUTER JOIN TWORK_MST_ICUTXTYPE ICUTXCTN ON OD.CTKEY = ICUTXCTN.CTKEY AND OD.OWKEY = ICUTXCTN.OWKEY AND OD.ICKEY = ICUTXCTN.ICKEY AND OD.ICUNITKEY = ICUTXCTN.ICUNITKEY AND ICUTXCTN.ICUNITTYPECD = 'CTN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE ICUTXINN ON OD.CTKEY = ICUTXINN.CTKEY AND OD.OWKEY = ICUTXINN.OWKEY AND OD.ICKEY = ICUTXINN.ICKEY AND OD.ICUNITKEY = ICUTXINN.ICUNITKEY AND ICUTXINN.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_BOX BOX ON OH.CTKEY = BOX.CTKEY AND OH.RECOMBOXBARCODE = BOX.BOXBARCODE WHERE OH.CTKEY = #{CTKEY} AND OH.OWKEY = COALESCE(#{OWKEY}, #{sowkey}) AND OH.OBHDDAY BETWEEN #{OBHDDAY_FROM} AND #{OBHDDAY_TO} AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.WAHDKEY IS NULL GROUP BY OH.CTKEY /*센터코드*/ , OH.OWKEY /*화주코드*/ , OH.OBHDDAY /*주문지시일시*/ , OH.OBREQDATE /*출고희망일자*/ , OH.OBORDKEY /*오더코드*/ , OH.OBHDKEY /*릴리즈코드*/ , OH.EXTERNORDERKEY /*고객주문번호*/ , OH.OBHDTYPECD /*출고유형*/ , OH.OBSTATUSCD /*출고상태*/ , OH.ORDSEPTYPECD /*주문유형*/ , OH.WKTYPECD /*작업유형*/ , OH.WBLNO /*송장번호*/ , OH.RECOMBOXBARCODE /*추천박스*/ , BOX.BOXNM /*추천박스명*/ , OH.CMT /*비고*/ , OH.ORDSEPURKEY /*주문분리자*/ , OH.ORDSEPDATE /*주문분리일시*/ , OH.INSERTURKEY /*등록자*/ , OH.INSERTDATE /*등록일시*/ , OH.UPDATEURKEY /*수정자*/ , OH.UPDATEDATE /*수정일시*/ , OH.CBM /*CBM*/ , OH.WEIGHT /*중량*/ , OH.WAHDKEY , OH.CLASSIFSPECCD , OH.OBWKISTURKEY ) OB WHERE 1=1
AND #{SEARCH_CONDITION}
AND CTN_YN IN ('O', 'Y')
AND CTN_YN = #{CTNYN}

mapper.select:
/* wms-outbound-obOrdSep-sql-oracle.xml - selectObSepCount - WMS > 출고 관리 > 출고편집 조회 카운트 */

SELECT COUNT(1)
  FROM OB_RESULT

/* wms-outbound-obOrdSep-sql-oracle.xml - selectObSepObHdCount - WMS > 출고 관리 > 출고편집 헤더 카운트 */

SELECT COUNT(DISTINCT OBHDKEY)
  FROM OB_RESULT

/* wms-outbound-obOrdSep-sql-oracle.xml - selectObSep - WMS > 출고 관리 > 출고편집 조회 */
#{GRIDPAGING_ROWNUMTYPE_TOP}

SELECT *
  FROM OB_RESULT
 ORDER BY
	   OBORDKEY
	 , OBHDKEY
	 , ICKEY
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-outbound-obOrdSep-sql-oracle.xml - selectObSepSummarySep - WMS > 출고 관리 > 출고편집 > 출고요약장표 조회(주문유형) */ SELECT ORDSEPTYPECD , COUNT(*) AS SEP_CNT , ROUND(COUNT(*)::NUMERIC / NULLIF(SUM(COUNT(*)) OVER(), 0) * 100, 2) AS SEP_RATIO FROM TWORK_INFO_OB_HD WHERE CTKEY = #{ctkey} AND OWKEY = COALESCE(#{owkey}, #{sowkey}) AND OBHDDAY BETWEEN #{obhddayFr} AND #{obhddayTo}
AND WKTYPECD = #{wktypecd}
AND OBSTATUSCD = '00' AND OBHDTYPECD IN ('10','20') AND WAHDKEY IS NULL GROUP BY ORDSEPTYPECD ORDER BY ORDSEPTYPECD

/* wms-outbound-obOrdSep-sql-oracle.xml - selectObOrdSummaryWk - WMS > 출고 관리 > 출고 현황 > 출고요약장표 조회(작업유형) */ SELECT WKTYPECD , COUNT(*) AS WK_CNT , ROUND(COUNT(*)::NUMERIC / NULLIF(SUM(COUNT(*)) OVER(), 0) * 100, 2) AS WK_RATIO FROM TWORK_INFO_OB_HD WHERE CTKEY = #{ctkey} AND OWKEY = COALESCE(#{owkey}, #{sowkey}) AND OBHDDAY BETWEEN #{obhddayFr} AND #{obhddayTo}
AND WKTYPECD = #{wktypecd}
AND OBSTATUSCD = '00' AND OBHDTYPECD IN ('10','20') AND WAHDKEY IS NULL GROUP BY WKTYPECD ORDER BY WKTYPECD

mapper.sql:
SELECT OH.CTKEY , OH.OWKEY , OD.ICKEY , IC.ICNM , IC.LCKEY , COUNT(DISTINCT OH.OBHDKEY) AS ORDCNT , SUM(OD.EXPCTQTY) AS ORDQTY FROM TWORK_INFO_OB_HD OH INNER JOIN TWORK_INFO_OB_DT OD ON OD.CTKEY = OH.CTKEY AND OD.OWKEY = OH.OWKEY AND OD.OBHDKEY = OH.OBHDKEY LEFT JOIN TWORK_MST_IC IC ON IC.CTKEY = OD.CTKEY AND IC.OWKEY = OD.OWKEY AND IC.ICKEY = OD.ICKEY WHERE OH.CTKEY = #{ctkey} AND OH.OWKEY = COALESCE(#{owkey}, #{sowkey}) AND OH.OBHDDAY BETWEEN RPAD(#{frdate}, 14, '0') AND RPAD(#{todate}, 14, '0')
AND OH.WKTYPECD = #{wktypecd}
AND OH.OBSTATUSCD = '00' AND OH.OBHDTYPECD IN ('10','20') AND OH.WAHDKEY IS NULL
#{item}
GROUP BY OH.CTKEY , OH.OWKEY , OD.ICKEY , IC.ICNM , IC.LCKEY

