mapper.delete:
/* wms-outbound-obOrdSep-sql-oracle.xml - deleteObSepTempStg - WMS > 출고 관리 > 출고편집 > 자동분리 - 저장한 임시 전략 삭제 */
DELETE FROM TWORK_INFO_ORD_SEP_TEMP
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND ORDSEPTEMPCD = #{ordseptempcd}

/* wms-outbound-ObOrdSepManagerMapper-sql-oracle.xml - deleteObSepPopInfoRvtObDt - WMS > 출고 관리 > 출고편집 > 출고주문정보 상세 > 원복 - 기존 출고정보 상세 삭제 */
DELETE FROM TWORK_INFO_OB_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBORDKEY = #{obordkey}

/* wms-outbound-ObOrdSepManagerMapper-sql-oracle.xml - deleteObSepPopInfoRvtObHd - WMS > 출고 관리 > 출고편집 > 출고주문정보 상세 > 원복 - 기존 출고정보 헤더 삭제 */
DELETE FROM TWORK_INFO_OB_HD
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBORDKEY = #{obordkey}
